                    encoding_error[i] = 0;
                end
                MLDSA_Q-1: begin
                    encoded_coeffs[i] = 3;
                    encoding_error[i] = 0;
                end
                MLDSA_Q-2: begin
                    encoded_coeffs[i] = 4;
                    encoding_error[i] = 0;
                end
                default: begin
                    encoded_coeffs[i] = 0;
                    encoding_error[i] = 1;
                end
            endcase
            unique case(mem_b_rd_data[i])
                REG_SIZE'(0): begin
                    encoded_coeffs[i+4] = 2;
                    encoding_error[i+4] = 0;
                end
                REG_SIZE'(1): begin
                    encoded_coeffs[i+4] = 1;
                    encoding_error[i+4] = 0;
                end
                REG_SIZE'(2): begin
                    encoded_coeffs[i+4] = 0;
                    encoding_error[i+4] = 0;
                end
                MLDSA_Q-1: begin
                    encoded_coeffs[i+4] = 3;
                    encoding_error[i+4] = 0;
                end
                MLDSA_Q-2: begin
                    encoded_coeffs[i+4] = 4;
                    encoding_error[i+4] = 0;
                end
                default: begin
                    encoded_coeffs[i+4] = 0;
                    encoding_error[i+4] = 1;
                end
            endcase
        end
    end : encoding

    assign error_flag = (|encoding_error) & mem_rd_data_valid;

    `ABR_ASSERT_NEVER(SKENCODE_ERROR_FLAG, error_flag, clk, !reset_n)

